import { Component, onMounted, onWillUnmount, reactive, useSubEnv } from "@odoo/owl";
import { Dropdown } from "@web/core/dropdown/dropdown";
import { DropdownItem } from "@web/core/dropdown/dropdown_item";
import { _t } from "@web/core/l10n/translation";
import { registry } from "@web/core/registry";
import { patch } from "@web/core/utils/patch";
import { useBus } from "@web/core/utils/hooks";
import { STATIC_ACTIONS_GROUP_NUMBER } from "@web/search/action_menus/action_menus";
import { FormController } from "@web/views/form/form_controller";
import { PropertiesField } from "./properties_field";

const MOUNTED_FIELDS_KEY = "_propertiesMountedFields";

/**
 * Inject a reactive registry into the env so every descendant of FormController
 * (PropertiesField instances AND the cog menu component) shares the same object.
 *
 * Also hide the generic "Edit Properties" item when the arch has >1 props fields
 * to let user choose which one edit
 */
patch(FormController.prototype, {
    setup() {
        super.setup(...arguments);
        const propertiesFieldNames = new Set(
            Object.values(this.archInfo.fieldNodes)
                .filter((n) => n.type === "properties")
                .map((n) => n.name)
        );
        useSubEnv({
            [MOUNTED_FIELDS_KEY]: reactive({}),
            _propertiesFieldCount: propertiesFieldNames.size,
        });
    },
    getStaticActionMenuItems() {
        const items = super.getStaticActionMenuItems();
        if (this.env._propertiesFieldCount > 1) {
            items.addPropertyFieldValue.isAvailable = () => false;
        }
        return items;
    },
});

/**
 * Register each PropertiesField in the shared env registry when it mounts so the
 * cog menu always reflects which fields are currently visible.
 *
 * Notebook tabs unmount their content on tab switch, so fields in inactive tabs
 * are automatically absent from the registry.
 *
 * Also register a field-specific bus event PROPERTY_FIELD:EDIT:<name> so only the
 * targeted field enters edit mode when selected from the multi-prop dropdown.
 */
patch(PropertiesField.prototype, {
    setup() {
        super.setup(...arguments);
        if (this.env.config?.viewType === "form") {
            const mountedRegistry = this.env[MOUNTED_FIELDS_KEY];
            if (mountedRegistry) {
                onMounted(() => {
                    mountedRegistry[this.props.name] = {
                        name: this.props.name,
                        string: this.props.record.fields[this.props.name]?.string,
                    };
                });
                onWillUnmount(() => {
                    delete mountedRegistry[this.props.name];
                });
            }
            useBus(this.env.model.bus, `PROPERTY_FIELD:EDIT:${this.props.name}`, async () => {
                if (this.props.readonly || this.state.isInEditMode) {
                    return;
                }
                let canChangeDefinition = this.state.canChangeDefinition;
                if (!canChangeDefinition) {
                    canChangeDefinition = await this.checkDefinitionWriteAccess();
                    if (!canChangeDefinition) {
                        this.notification.add(this._getPropertyEditWarningText(), {
                            type: "warning",
                        });
                    }
                }
                const isInEditMode = canChangeDefinition && !this.props.readonly;
                this.state.canChangeDefinition = !!canChangeDefinition;
                this.state.isInEditMode = isInEditMode;
                if (isInEditMode && this.propertiesList.length === 0) {
                    this.onPropertyCreate();
                }
            });
        }
    },
});

/**
 * CogMenu registry component for form views with multiple properties fields.
 * Reads env[MOUNTED_FIELDS_KEY] which is reactive, auto-updates on tab switch.
 *
 *   2+ mounted -> nested dropdown listing each field by its label
 *   1 mounted  -> simple DropdownItem (graceful fallback)
 *   0 mounted  -> renders nothing
 */
class PropertiesEditMenuItem extends Component {
    static template = "web.PropertiesEditMenuItem";
    static components = { Dropdown, DropdownItem };
    static props = ["*"];

    get label() {
        return _t("Edit Properties");
    }

    get propertiesFields() {
        return Object.values(this.env[MOUNTED_FIELDS_KEY] || {}).sort((a, b) =>
            a.name.localeCompare(b.name)
        );
    }

    editProperty(fieldName) {
        this.env.model.bus.trigger(`PROPERTY_FIELD:EDIT:${fieldName}`);
    }
}

registry.category("cogMenu").add("properties-edit-multi", {
    Component: PropertiesEditMenuItem,
    groupNumber: STATIC_ACTIONS_GROUP_NUMBER,
    isDisplayed: (env) => env.config?.viewType === "form" && env._propertiesFieldCount > 1,
});

